import numpy as np
import networkx as nx

def find_superpixel_3d(Yt: np.ndarray, num_plane: int, cut_off_point: float, length_cut: int, length_max: int, eight_neighbours: bool = True) -> tuple:
    """
    This function identifies and labels connected components in a 3D array.

    Parameters:
    Yt (np.ndarray): A 3D numpy array of shape (D1, D2, D3).
    num_plane (int): An integer representing the number of planes in the second dimension.
    cut_off_point (float): A float representing the threshold for connectivity.
    length_cut (int): An integer representing the minimum size of components to consider.
    length_max (int): An integer representing the maximum size of components to consider.
    eight_neighbours (bool): A boolean indicating whether to consider diagonal neighbors.

    Returns:
    tuple: A tuple containing the reshaped labeled array, the number of valid components, a list of connected components, and the permutation of labels.
    """

    # Input Reshaping
    D1, D2, D3 = Yt.shape
    Yt_3d = Yt.reshape(D1, D2 // num_plane, num_plane, D3)

    # Reference Matrix Creation
    ref_mat = np.arange(D1 * (D2 // num_plane) * num_plane * D3).reshape(D1, D2 // num_plane, num_plane, D3)

    # Normalization
    Yt_3d = (Yt_3d - np.mean(Yt_3d, axis=-1, keepdims=True)) / np.std(Yt_3d, axis=-1, keepdims=True)
    Yt_3d = np.nan_to_num(Yt_3d)

    # Correlation Calculation
    rho_v = np.zeros((D1 - 1, D2 // num_plane, num_plane, D3))
    rho_h = np.zeros((D1, (D2 // num_plane) - 1, num_plane, D3))
    rho_u = np.zeros((D1, D2 // num_plane, num_plane - 1, D3))
    if eight_neighbours:
        rho_l = np.zeros((D1 - 1, (D2 // num_plane) - 1, num_plane, D3))
        rho_r = np.zeros((D1 - 1, (D2 // num_plane) - 1, num_plane, D3))

    for i in range(D1 - 1):
        for j in range(D2 // num_plane):
            for k in range(num_plane):
                for m in range(D3):
                    rho_v[i, j, k, m] = np.corrcoef(Yt_3d[i, j, k, m], Yt_3d[i + 1, j, k, m])[0, 1]

    for i in range(D1):
        for j in range((D2 // num_plane) - 1):
            for k in range(num_plane):
                for m in range(D3):
                    rho_h[i, j, k, m] = np.corrcoef(Yt_3d[i, j, k, m], Yt_3d[i, j + 1, k, m])[0, 1]

    for i in range(D1):
        for j in range(D2 // num_plane):
            for k in range(num_plane - 1):
                for m in range(D3):
                    rho_u[i, j, k, m] = np.corrcoef(Yt_3d[i, j, k, m], Yt_3d[i, j, k + 1, m])[0, 1]

    if eight_neighbours:
        for i in range(D1 - 1):
            for j in range((D2 // num_plane) - 1):
                for k in range(num_plane):
                    for m in range(D3):
                        rho_l[i, j, k, m] = np.corrcoef(Yt_3d[i, j, k, m], Yt_3d[i + 1, j + 1, k, m])[0, 1]
                        rho_r[i, j, k, m] = np.corrcoef(Yt_3d[i, j, k, m], Yt_3d[i + 1, j + 1, k, m])[0, 1]

    # Padding Correlation Arrays
    rho_v = np.pad(rho_v, ((0, 1), (0, 0), (0, 0), (0, 0)), mode='constant')
    rho_h = np.pad(rho_h, ((0, 0), (0, 1), (0, 0), (0, 0)), mode='constant')
    rho_u = np.pad(rho_u, ((0, 0), (0, 0), (0, 1), (0, 0)), mode='constant')
    if eight_neighbours:
        rho_l = np.pad(rho_l, ((0, 1), (0, 1), (0, 0), (0, 0)), mode='constant')
        rho_r = np.pad(rho_r, ((0, 1), (0, 1), (0, 0), (0, 0)), mode='constant')

    # Thresholding
    A = []
    B = []
    for i in range(D1):
        for j in range(D2 // num_plane):
            for k in range(num_plane):
                for m in range(D3):
                    if i < D1 - 1 and rho_v[i, j, k, m] > cut_off_point:
                        A.append(ref_mat[i, j, k, m])
                        B.append(ref_mat[i + 1, j, k, m])
                    if j < (D2 // num_plane) - 1 and rho_h[i, j, k, m] > cut_off_point:
                        A.append(ref_mat[i, j, k, m])
                        B.append(ref_mat[i, j + 1, k, m])
                    if k < num_plane - 1 and rho_u[i, j, k, m] > cut_off_point:
                        A.append(ref_mat[i, j, k, m])
                        B.append(ref_mat[i, j, k + 1, m])
                    if eight_neighbours:
                        if i < D1 - 1 and j < (D2 // num_plane) - 1 and rho_l[i, j, k, m] > cut_off_point:
                            A.append(ref_mat[i, j, k, m])
                            B.append(ref_mat[i + 1, j + 1, k, m])
                        if i < D1 - 1 and j < (D2 // num_plane) - 1 and rho_r[i, j, k, m] > cut_off_point:
                            A.append(ref_mat[i, j, k, m])
                            B.append(ref_mat[i + 1, j + 1, k, m])

    # Graph Construction
    G = nx.Graph()
    G.add_edges_from(zip(A, B))

    # Connected Components Identification
    components = list(nx.connected_components(G))

    # Filtering Components
    valid_components = [component for component in components if length_cut < len(component) < length_max]

    # Labeling Components
    labels = np.zeros(D1 * D2 * D3)
    for i, component in enumerate(valid_components):
        for index in component:
            labels[index] = i + 1

    # Output Reshaping
    labeled_array = labels.reshape(D1, D2, D3)

    # Return Values
    num_valid_components = len(valid_components)
    permutation = np.random.permutation(num_valid_components)

    return labeled_array, num_valid_components, valid_components, permutation
