def sp1(data, maxvalue, issuccessful):
    # Input Validation
    if not isinstance(data, (list, tuple, np.ndarray)):
        return np.nan, np.nan, np.nan
    if issuccessful is not None and not isinstance(issuccessful, (list, tuple, np.ndarray)):
        return np.nan, np.nan, np.nan
    if issuccessful is not None and len(issuccessful) != len(data):
        return np.nan, np.nan, np.nan

    # Data Cleaning
    if issuccessful is not None:
        issuccessful = [x for x, y in zip(issuccessful, data) if not np.isnan(y)]
    dat = [x for x in data if not np.isnan(x)]

    # Handling Empty Data
    if not dat:
        return np.nan, np.nan, np.nan

    # Filtering Data Based on Success
    if issuccessful is not None:
        dat = [x for x, y in zip(dat, issuccessful) if y]
    else:
        dat = [x for x in dat if x < maxvalue]

    # Calculating Success Ratio
    N = len([x for x in data if not np.isnan(x)])
    succ = len(dat) / N

    # Returning Results
    if succ == 0:
        return np.inf, 0.0, 0
    else:
        return np.mean(dat) / succ, succ, len(dat)
