    # Data Cleaning
    dat = [x for x in data if not np.isnan(x)]
    N = len(dat)

    # Empty Data Handling
    if N == 0:
        return np.nan, np.nan, np.nan

    # Sorting Data
    dat.sort()

    # Successful Data Filtering
    if issuccessful is not None:
        succdat = [x for x, y in zip(dat, issuccessful) if y]
    else:
        succdat = [x for x in dat if x < maxvalue]

    # Success Rate Calculation
    succ = len(succdat) / N if N > 0 else 0

    # Result Calculation
    if succ == 0:
        if allowinf:
            res = np.inf
        else:
            res = sum(dat)
    else:
        if succdat:
            res = sum(dat) / len(succdat)
        else:
            res = np.nan

    # Return Statement
    return res, succ, len(succdat)

