import numpy as np

def augment_img(img: np.ndarray, mode: int) -> np.ndarray:
    """
    Applies various augmentations to a given 2D image represented as a NumPy array.

    Args:
    img (np.ndarray): A 2D NumPy array representing the image.
    mode (int): An integer that determines the type of augmentation to apply.

    Returns:
    np.ndarray: A 2D NumPy array representing the augmented image after applying the specified transformation based on the mode.
    """

    # Check if the input image is empty or not a 2D array
    if img.size == 0 or img.ndim != 2:
        return img

    # Apply transformations based on the mode
    if mode == 0:
        # Return the original image
        return img
    elif mode == 1:
        # Flip the image upside down and rotate it 90 degrees counterclockwise
        return np.rot90(np.flipud(img), 1)
    elif mode == 2:
        # Flip the image upside down without any rotation
        return np.flipud(img)
    elif mode == 3:
        # Rotate the image 270 degrees counterclockwise (or 90 degrees clockwise)
        return np.rot90(img, -1)
    elif mode == 4:
        # Flip the image upside down and rotate it 180 degrees
        return np.rot90(np.flipud(img), 2)
    elif mode == 5:
        # Rotate the image 90 degrees counterclockwise
        return np.rot90(img, 1)
    elif mode == 6:
        # Rotate the image 180 degrees
        return np.rot90(img, 2)
    elif mode == 7:
        # Flip the image upside down and rotate it 270 degrees counterclockwise (or 90 degrees clockwise)
        return np.rot90(np.flipud(img), -1)
    else:
        # Return the original image for invalid modes
        return img

