import numpy as np

def logbins_numba(lo: float, hi: float, ratio: float, N: int, prepend_zero: bool) -> np.ndarray:
    # Convert lower and upper bounds to integers
    lo = int(lo)
    hi = int(hi)

    # Determine number of points (N)
    if ratio != 0 and N == 0:
        N = int(np.log(hi / lo) / np.log(ratio))
    if N == 0:
        N = 10

    # Ensure minimum points
    N = max(1, N)

    # Generate logarithmic sequence
    log_lo = np.log10(lo)
    log_hi = np.log10(hi)
    log_seq = np.logspace(log_lo, log_hi, N)
    seq = np.round(log_seq).astype(int)

    # Unique and sorted values
    seq = np.unique(seq)
    seq = np.sort(seq)

    # Boundary conditions
    if len(seq) == 0:
        if prepend_zero:
            return np.array([0])
        else:
            return np.array([])
    if seq[0] != lo:
        seq = np.insert(seq, 0, lo)
    if seq[-1] != hi:
        seq = np.append(seq, hi)

    # Prepend zero
    if prepend_zero:
        seq = np.insert(seq, 0, 0)

    return seq
