def qam_mod(M):
    """
    This function generates a mapping and demapping table for Quadrature Amplitude Modulation (QAM) based on a given modulation order M.

    Parameters:
    M (int): The modulation order for QAM.

    Returns:
    tuple: A tuple containing two dictionaries. The first dictionary is the mapping table from Gray code to constellation points, 
           and the second dictionary is the demapping table from constellation points back to Gray code.
    """

    # Calculate the square root of M and convert it to an integer
    sqrtM = int(M ** 0.5)

    # Define a dictionary for special cases
    special_cases = {
        8: {
            'gray_code': [0, 1, 3, 2, 4, 5, 7, 6],
            'constellation_points': [(-1-1j), (-1-3j), (1-3j), (1-1j), (-1+1j), (-1+3j), (1+3j), (1+1j)]
        },
        32: {
            'gray_code': [0, 1, 3, 2, 4, 5, 7, 6, 8, 9, 11, 10, 12, 13, 15, 14, 16, 17, 19, 18, 20, 21, 23, 22, 24, 25, 27, 26, 28, 29, 31, 30],
            'constellation_points': []
        }
    }

    # Check if M is a special case
    if M in special_cases:
        if M == 8:
            gray_code = special_cases[M]['gray_code']
            constellation_points = special_cases[M]['constellation_points']
        elif M == 32:
            gray_code = special_cases[M]['gray_code']
            constellation_points = []
            for i in range(8):
                for j in range(4):
                    constellation_points.append((i-3.5) + (j-1.5)*1j)
    else:
        # Generate Gray code
        gray_code = []
        for i in range(M):
            gray_code.append(i ^ (i >> 1))

        # Generate constellation points
        constellation_points = []
        for i in range(sqrtM):
            for j in range(sqrtM):
                constellation_points.append((i-(sqrtM-1)/2) + (j-(sqrtM-1)/2)*1j)

    # Create mapping table
    map_table = {gray_code[i]: constellation_points[i] for i in range(M)}

    # Create demapping table
    demap_table = {v: k for k, v in map_table.items()}

    return map_table, demap_table

