import numpy as np

def process_parameters_psd(dim, mean, cov):
    # Dimension Initialization
    if dim is None:
        dim = 1

    # Mean Processing
    if mean is not None:
        mean = np.array(mean, dtype=float)
        dim = len(mean)
    elif cov is not None:
        cov = np.array(cov)
        if cov.ndim == 1:
            dim = 1
        else:
            dim = cov.shape[0]

    # Default Mean and Covariance Initialization
    if mean is None:
        mean = np.zeros(dim)
    if cov is None:
        cov = 1.0

    # Reshaping for Single Dimension
    if dim == 1:
        mean = mean.reshape(-1)
        if np.isscalar(cov) or cov.ndim == 0:
            cov = cov.reshape(1, 1)
        elif cov.ndim == 1:
            cov = np.diag(cov)

    # Covariance Matrix Formatting
    if cov.ndim == 0:
        cov = cov * np.eye(dim)
    elif cov.ndim == 1:
        cov = np.diag(cov)
    elif cov.ndim == 2 and cov.shape != (dim, dim):
        if cov.shape[0] != cov.shape[1]:
            cov = np.eye(dim)
        else:
            cov = np.zeros((dim, dim))
    elif cov.ndim > 2:
        cov = np.eye(dim)

    return dim, mean, cov

