from sklearn.manifold import TSNE

def run_tsne(data, group, drop_cols, annotation_cols, components, perplexity, max_iter, init, dropna):
    result = {}
    args = {}

    df = data.copy()

    if df.shape[0] < 2 or len(df.select_dtypes(include=['int64', 'float64']).columns) < 2:
        return result, args

    if all(col in df.columns for col in drop_cols):
        df = df.drop(columns=drop_cols)

    df.set_index(group, inplace=True)
    if dropna:
        df = df.dropna(axis=1)
    df = df.select_dtypes(include=['int64', 'float64'])

    if df.shape[0] < 2 or df.shape[1] < 2:
        return result, args

    X = df.values
    y = df.index
    annotations = pd.DataFrame()

    if annotation_cols:
        for col in annotation_cols:
            if col in data.columns:
                annotations[col] = data[col]

    if X.size > 0:
        tsne = TSNE(n_components=components, perplexity=perplexity, max_iter=max_iter, init=init)
        X_tsne = tsne.fit_transform(X)

        args['x_title'] = 'C1'
        args['y_title'] = 'C2'

        if components == 2:
            resultDf = pd.DataFrame({'group': y, 'x': X_tsne[:, 0], 'y': X_tsne[:, 1]})
        else:
            resultDf = pd.DataFrame({'group': y, 'x': X_tsne[:, 0], 'y': X_tsne[:, 1], 'z': X_tsne[:, 2]})
            args['z_title'] = 'C3'

        if not annotations.empty:
            resultDf = pd.merge(resultDf, annotations, left_on='group', right_index=True)

        result['tsne'] = resultDf

    return result, args
