import numpy as np

def cat_var(data, col_excl=None, return_cat=True):
    # Copy the DataFrame
    data_copy = data.copy()

    # Identify Non-Numeric Columns
    if col_excl is None:
        non_numeric_cols = [col for col in data_copy.columns if not pd.api.types.is_numeric_dtype(data_copy[col])]
    else:
        non_numeric_cols = [col for col in data_copy.columns if not pd.api.types.is_numeric_dtype(data_copy[col]) and col not in col_excl]

    # Get Indices of Categorical Variables
    cat_var_indices = [data_copy.columns.get_loc(col) for col in non_numeric_cols]

    # Create a DataFrame for Categorical Variables
    cat_var_df = pd.DataFrame({'cat_ind': cat_var_indices, 'cat_name': non_numeric_cols})

    # Convert Date Columns to String
    for col in data_copy.columns:
        if 'date' in col.lower():
            data_copy[col] = data_copy[col].astype(str)

    # Prepare for Mapping
    inv_mapper = {}
    mapper = {}
    for col in non_numeric_cols:
        unique_values = data_copy[col].unique()
        inv_mapper[col] = {i: val for i, val in enumerate(unique_values)}
        mapper[col] = {val: i for i, val in enumerate(unique_values)}

    # Map Categorical Values
    for col in non_numeric_cols:
        data_copy[col] = data_copy[col].map(mapper[col]).fillna(0).astype(int)

    # Return Categorical DataFrame
    if return_cat:
        for col in non_numeric_cols:
            data_copy[col] = pd.Categorical(data_copy[col])

    return data_copy, cat_var_df, inv_mapper, mapper

