import pandas as pd
from scipy import stats

def validate_results(real_sim_dict):
    val_results = []

    for variable, (real_data, simulated_data) in real_sim_dict.items():
        real_list = np.array(real_data).flatten()
        simulation_list = simulated_data['simulated'].values.flatten()

        if len(real_list) == 0 or len(simulation_list) == 0:
            val_results.append({
                'variable': variable,
                'error': 'Either real or simulated data is empty'
            })
            continue

        if len(real_list) != len(simulation_list):
            simulation_list = simulation_list[:len(real_list)]

        ks_stat, ks_p_value = stats.ks_2samp(real_list, simulation_list)

        if ks_p_value >= 0.05:
            distribution_similarity = 'Two distributions are similar'
        else:
            distribution_similarity = 'Two distributions are not similar'

        statistical_comparison = {
            'mean': {
                'reality': np.mean(real_list),
                'simulated': np.mean(simulation_list)
            },
            'STD': {
                'reality': np.std(real_list),
                'simulated': np.std(simulation_list)
            },
            'CV': {
                'reality': np.std(real_list) / np.mean(real_list) if np.mean(real_list) != 0 else np.nan,
                'simulated': np.std(simulation_list) / np.mean(simulation_list) if np.mean(simulation_list) != 0 else np.nan
            }
        }

        diff_list = np.abs(real_list - simulation_list)
        acceptance_rate = (diff_list <= 0.2).mean() * 100

        shapiro_stat, shapiro_p_value = stats.shapiro(diff_list)

        if shapiro_p_value >= 0.05:
            normality_assessment = 'Difference is a normal distribution'
        else:
            normality_assessment = 'Difference is not a normal distribution'

        val_results.append({
            'variable': variable,
            'statistical_comparison': statistical_comparison,
            'ks_test_p_value': ks_p_value,
            'distribution_similarity': distribution_similarity,
            'acceptance_rate': acceptance_rate,
            'normality_assessment': normality_assessment
        })

    return val_results

