import numpy as np
from scipy.sparse import csr_matrix

def b_spline_basis(x, edge_knots, n_splines=20, spline_order=3, sparse=True, periodic=True):
    # Adjusting number of splines
    if periodic:
        n_splines = n_splines - spline_order + 1
    else:
        n_splines = n_splines

    # Sorting and scaling
    edge_knots = np.sort(edge_knots)
    offset = edge_knots[0]
    scale = edge_knots[-1] - edge_knots[0]

    # Boundary knots
    boundary_knots = np.linspace(0, 1, n_splines + spline_order + 1)

    # Normalization of input values
    x_normalized = (x - offset) / scale
    if periodic:
        x_normalized = np.mod(x_normalized, 1)

    # Extrapolation and interpolation flags
    extrapolation_flags = np.logical_or(x_normalized < 0, x_normalized > 1)
    interpolation_flags = np.logical_not(extrapolation_flags)

    # Augmented knots
    augmented_knots = np.concatenate((np.zeros(spline_order), boundary_knots, np.ones(spline_order)))

    # B-spline basis function calculation
    basis_functions = np.zeros((len(x), n_splines))
    for i in range(len(x)):
        if interpolation_flags[i]:
            basis_functions[i] = _calculate_basis_functions(x_normalized[i], augmented_knots, spline_order)
        else:
            basis_functions[i] = _extrapolate_basis_functions(x_normalized[i], augmented_knots, spline_order)

    # Handling periodicity
    if periodic:
        basis_functions = _adjust_periodic_basis_functions(basis_functions, spline_order)

    # Final output
    if sparse:
        return csr_matrix(basis_functions)
    else:
        return basis_functions


def _calculate_basis_functions(x, knots, order):
    basis_functions = np.zeros(len(knots) - order)
    for i in range(len(knots) - order):
        basis_functions[i] = _calculate_basis_function(x, knots, i, order)
    return basis_functions


def _calculate_basis_function(x, knots, i, order):
    if order == 0:
        if knots[i] <= x < knots[i + 1]:
            return 1
        else:
            return 0
    else:
        numerator1 = x - knots[i]
        denominator1 = knots[i + order] - knots[i]
        numerator2 = knots[i + order + 1] - x
        denominator2 = knots[i + order + 1] - knots[i + 1]
        if denominator1 == 0:
            term1 = 0
        else:
            term1 = numerator1 / denominator1 * _calculate_basis_function(x, knots, i, order - 1)
        if denominator2 == 0:
            term2 = 0
        else:
            term2 = numerator2 / denominator2 * _calculate_basis_function(x, knots, i + 1, order - 1)
        return term1 + term2


def _extrapolate_basis_functions(x, knots, order):
    if x < 0:
        return _extrapolate_basis_functions_left(x, knots, order)
    else:
        return _extrapolate_basis_functions_right(x, knots, order)


def _extrapolate_basis_functions_left(x, knots, order):
    basis_functions = np.zeros(len(knots) - order)
    for i in range(len(knots) - order):
        basis_functions[i] = _extrapolate_basis_function_left(x, knots, i, order)
    return basis_functions


def _extrapolate_basis_function_left(x, knots, i, order):
    if order == 0:
        return 0
    else:
        numerator1 = x - knots[i]
        denominator1 = knots[i + order] - knots[i]
        numerator2 = knots[i + order + 1] - x
        denominator2 = knots[i + order + 1] - knots[i + 1]
        if denominator1 == 0:
            term1 = 0
        else:
            term1 = numerator1 / denominator1 * _extrapolate_basis_function_left(x, knots, i, order - 1)
        if denominator2 == 0:
            term2 = 0
        else:
            term2 = numerator2 / denominator2 * _extrapolate_basis_function_left(x, knots, i + 1, order - 1)
        return term1 + term2


def _extrapolate_basis_functions_right(x, knots, order):
    basis_functions = np.zeros(len(knots) - order)
    for i in range(len(knots) - order):
        basis_functions[i] = _extrapolate_basis_function_right(x, knots, i, order)
    return basis_functions


def _extrapolate_basis_function_right(x, knots, i, order):
    if order == 0:
        return 0
    else:
        numerator1 = x - knots[i]
        denominator1 = knots[i + order] - knots[i]
        numerator2 = knots[i + order + 1] - x
        denominator2 = knots[i + order + 1] - knots[i + 1]
        if denominator1 == 0:
            term1 = 0
        else:
            term1 = numerator1 / denominator1 * _extrapolate_basis_function_right(x, knots, i, order - 1)
        if denominator2 == 0:
            term2 = 0
        else:
            term2 = numerator2 / denominator2 * _extrapolate_basis_function_right(x, knots, i + 1, order - 1)
        return term1 + term2


def _adjust_periodic_basis_functions(basis_functions, order):
    adjusted_basis_functions = np.copy(basis_functions)
    for i in range(order):
        adjusted_basis_functions[:, i] += basis_functions[:, -order + i]
    return adjusted_basis_functions


# Example usage
