import numpy as np

def _contains_nan(a, nan_policy):
    if nan_policy == 'omit':
        return np.isnan(a).any()
    elif nan_policy == 'propagate':
        return np.isnan(a).any()
    else:
        raise ValueError("Invalid nan_policy. It should be 'omit' or 'propagate'.")

def percentileofscore(a, score, kind, nan_policy):
    a = np.asarray(a)
    n = len(a)
    score = np.asarray(score)

    if _contains_nan(a, nan_policy):
        if nan_policy == 'omit':
            mask = ~np.isnan(a)
            a = a[mask]
            n = len(a)
        elif nan_policy == 'propagate':
            n = 0

    if _contains_nan(score, nan_policy):
        if nan_policy == 'omit':
            score_mask = ~np.isnan(score)
            score = score[score_mask]
        elif nan_policy == 'propagate':
            return np.full_like(score, np.nan)

    if n == 0:
        return np.full_like(score, np.nan)

    score = score.reshape(-1, 1)

    if kind == 'rank':
        less = np.sum(a < score, axis=0)
        equal = np.sum(a == score, axis=0)
        return (less + 0.5 * equal) / n * 100
    elif kind == 'strict':
        return np.sum(a < score, axis=0) / n * 100
    elif kind == 'weak':
        return np.sum(a <= score, axis=0) / n * 100
    elif kind == 'mean':
        return ((np.sum(a < score, axis=0) + np.sum(a <= score, axis=0)) / 2) / n * 100
    else:
        return np.full_like(score, np.nan)

a = np.array([0.1, 0.4, 0.5, 0.7, 0.9])
score = np.array([0.3, 0.6])
kind = 'rank'
nan_policy = 'omit'

print(percentileofscore(a, score, kind, nan_policy))
