from sklearn.model_selection import cross_validate

def _cross_validate(model, X_train, y_train):
    if model.estimator_type == 'classifier':
        scoring = ['accuracy', 'precision', 'recall', 'f1']
    elif model.estimator_type == 'regressor':
        scoring = ['r2', 'neg_mean_squared_error', 'neg_mean_absolute_error', 'explained_variance']
    else:
        raise ValueError("Invalid estimator type. It should be either 'classifier' or 'regressor'.")

    scores = cross_validate(model.pipe, X_train, y_train, scoring=scoring, cv=model.cv, return_train_score=False)

    if model.estimator_type == 'classifier':
        metrics = {
            'class': ['overall'],
            'accuracy': [scores['test_accuracy'].mean()],
            'precision': [scores['test_precision'].mean()],
            'recall': [scores['test_recall'].mean()],
            'f1': [scores['test_f1'].mean()]
        }
    elif model.estimator_type == 'regressor':
        metrics = {
            'r2': [scores['test_r2'].mean()],
            'neg_mean_squared_error': [scores['test_neg_mean_squared_error'].mean()],
            'neg_mean_absolute_error': [scores['test_neg_mean_absolute_error'].mean()],
            'explained_variance': [scores['test_explained_variance'].mean()]
        }

    if model.estimator_type == 'classifier':
        model.score = scores['test_accuracy'].mean()
    elif model.estimator_type == 'regressor':
        model.score = scores['test_r2'].mean()

    model.metrics_df = pd.DataFrame(metrics)
    return model.metrics_df
