import tensorflow as tf

def get_variable_from_tensor(var):
    # Check if var is a TensorFlow variable
    if isinstance(var, tf.Variable):
        return var

    # Check if var is a TensorFlow tensor
    if isinstance(var, tf.Tensor):
        # Check if var has an attribute 'op' and if the operation type of var is 'ReadVariableOp'
        if hasattr(var, 'op') and var.op.type == 'ReadVariableOp':
            var = var.op.inputs[0]

        # Check if the operation type of var is either 'VarHandleOp' or 'VariableV2'
        if hasattr(var, 'op') and var.op.type in ['VarHandleOp', 'VariableV2']:
            for v in tf.compat.v1.global_variables():
                if v.handle == var:
                    return v

        # Check if the operation type of var is 'Identity'
        if hasattr(var, 'op') and var.op.type == 'Identity':
            var = var.op.inputs[0]
            return get_variable_from_tensor(var)

    # If none of the conditions are met, return None
    return None

