import tensorflow as tf

def h2(u, x, dimension):
    with tf.GradientTape(persistent=True) as tape:
        tape.watch(x)
        ans = tf.reduce_mean(tf.square(u) + tf.square(tf.norm(tape.gradient(u, x), axis=1)))
        grad = tape.gradient(u, x)
        if grad is not None:
            for i in range(dimension):
                g = tape.gradient(grad[:, i], x)
                if g is not None:
                    ans += tf.reduce_mean(tf.square(g))
        if ans is not None:
            return tf.sqrt(ans)
        else:
            return tf.constant(0.0, dtype=tf.float32)

